import { RIView } from "../view/view.js";
import { RIModel } from "../model/model.js";

export class RIController {
  constructor() {
    this.view = new RIView();
    this.model = new RIModel();

    this.model
      .fetch_images()
      .then((res) => {
        console.log(res);
        this.view.render_all_images(res);
      })
      .catch((err) => {
        console.log(err);
      });
  }
}
