export class RIView {
  constructor() {}

  render_all_images = (fetch_images_result) => {
    console.log(fetch_images_result);

    // cache
    const parentDiv = document.getElementById(
      "resident_involvement_main_section2-div2",
    );

    const divForward = document.getElementById(
      "resident_involvement_main_section2-div-div-forwards-main",
    );

    const divBackward = document.getElementById(
      "resident_involvement_main_section2-div-div-backwards-main",
    );

    let currentDiv = null;

    let divIndex = 0;

    let changeDivSlide = 0;

    fetch_images_result.data.forEach((imgSrc, imgIndex) => {
      if (imgIndex % 4 === 0) {
        currentDiv = document.createElement("div");
        currentDiv.classList.add("resident_involvement_main_section2-div-div");
        currentDiv.setAttribute(
          "id",
          `resident_involvement_main_section2-div-div-${divIndex}`,
        );

        parentDiv.append(currentDiv);

        divIndex++;

        if (divIndex > 2) {
          currentDiv.style.display = "none";
        }
      }

      const img = document.createElement("img");

      if (process.env.NODE_ENV === "production") {
        img.setAttribute("src", imgSrc.image_prod_url);
      } else {
        img.setAttribute("src", imgSrc.image_dev_url);
      }

      img.classList.add("resident_involvement_main_section2-div-div-img");

      img.alt = `photo for image id:${imgSrc.image_id}`;

      img.addEventListener("click", () => {
        if (process.env.NODE_ENV === "production") {
          this.full_screen_images(imgSrc.image_prod_url);
        } else {
          this.full_screen_images(imgSrc.image_dev_url);
        }
      });
      console.log(img.getAttribute("src"));

      currentDiv.appendChild(img);
    });

    this.render_image_galleries(fetch_images_result.data);

    divForward.addEventListener("click", (event) => {
      const divs = Array.from(
        document.getElementsByClassName(
          "resident_involvement_main_section2-div-div",
        ),
      );

      for (
        let i = changeDivSlide;
        i < changeDivSlide + 2 && i < divs.length;
        i++
      ) {
        divs[i].style.display = "none";
      }

      changeDivSlide += 2;

      if (changeDivSlide >= divs.length) {
        if (divs.length % 2 === 0) {
          // if even number, show the last 2
          changeDivSlide = divs.length - 2;
        } else {
          // if odd number, show the very last 1
          changeDivSlide = divs.length - 1;
        }
      }

      for (
        let i = changeDivSlide;
        i < changeDivSlide + 2 && i < divs.length;
        i++
      ) {
        divs[i].style.display = "flex";
      }
    });

    divBackward.addEventListener("click", (event) => {
      const divs = Array.from(
        document.getElementsByClassName(
          "resident_involvement_main_section2-div-div",
        ),
      );

      for (
        let i = changeDivSlide;
        i < changeDivSlide + 2 && i < divs.length;
        i++
      ) {
        divs[i].style.display = "none";
      }

      changeDivSlide -= 2;

      if (changeDivSlide < 0) {
        changeDivSlide = 0;
      }

      for (
        let i = changeDivSlide;
        i < changeDivSlide + 2 && i < divs.length;
        i++
      ) {
        divs[i].style.display = "flex";
      }
    });
  };

  full_screen_images = (imageSrc) => {
    // display modal for images
    const modalDiv = document.getElementById(
      "resident_involvement_main_section2-div-div3",
    );

    modalDiv.setAttribute("id", "resident_involvement_main_section2-div-div3");

    modalDiv.style.display = "flex";

    // set corect image src for modal
    const img = document.getElementById(
      "resident_involvement_main_section2-div-div3-img",
    );

    img.setAttribute("src", imageSrc);

    // close modal
    const closeButton = document.getElementById(
      "resident_involvement_main_section2-div-div3-x",
    );

    closeButton.addEventListener("click", () => {
      modalDiv.style.display = "none";
    });
  };

  render_image_galleries = (images) => {
    const array2 = Object.values(
      images.reduce((acc, img) => {
        if (!img.image_category) return acc;

        if (!acc[img.image_category])
          acc[img.image_category] = {
            categoryName: img.image_category,
            images: [],
          };

        acc[img.image_category].images.push(img);
        return acc;
      }, {}),
    );

    const mainSection = document.getElementById(
      "resident_involvement_main_section3",
    );

    array2.forEach((category) => {
      let currentIndex = 0;

      const article = document.createElement("article");
      const div1 = document.createElement("div");
      const h3 = document.createElement("h3");
      const btnBack = document.createElement("div");
      const btnForward = document.createElement("div");
      const imagesWrapper = document.createElement("div"); // wrapper for fade

      article.classList.add("resident_involvement_main_articles");
      h3.classList.add("resident_involvement_main_articles-h3");
      div1.classList.add("resident_involvement_main_articles-div");

      btnBack.classList.add(
        "resident_involvement_main_section2-div-div-backwards",
      );
      btnBack.textContent = "<";
      btnBack.setAttribute(
        "id",
        "resident_involvement_main_articles_div_div_backward",
      );

      btnForward.setAttribute(
        "id",
        "resident_involvement_main_articles_div_div_forward",
      );
      btnForward.classList.add(
        "resident_involvement_main_section2-div-div-forwards",
      );
      btnForward.textContent = ">";

      h3.textContent = category.categoryName;

      // Add fade class to wrapper
      imagesWrapper.classList.add("fade-container");

      mainSection.append(article);
      article.append(h3, div1);
      div1.append(btnBack, imagesWrapper, btnForward);

      const renderChunk = () => {
        // fade out
        imagesWrapper.classList.add("fade-out");

        setTimeout(() => {
          // Clear old images
          imagesWrapper.innerHTML = "";

          // Render new chunk
          const chunk = category.images.slice(currentIndex, currentIndex + 4);
          chunk.forEach((imgData) => {
            const newImg = document.createElement("img");
            newImg.classList.add("resident_involvement_main_articles-div-img");
            newImg.setAttribute(
              "src",
              process.env.NODE_ENV === "production"
                ? imgData.image_prod_url
                : imgData.image_dev_url,
            );
            newImg.addEventListener("click", () => {
              if (process.env.NODE_ENV === "production") {
                this.full_screen_images(imgData.image_prod_url);
              } else {
                this.full_screen_images(imgData.image_dev_url);
              }
            });
            imagesWrapper.appendChild(newImg);
          });

          // fade back in
          imagesWrapper.classList.remove("fade-out");
        }, 400); // match CSS duration
      };

      // Initial render
      renderChunk();

      btnForward.addEventListener("click", () => {
        if (currentIndex + 4 < category.images.length) {
          currentIndex += 4;
          renderChunk();
        }
      });

      btnBack.addEventListener("click", () => {
        if (currentIndex - 4 >= 0) {
          currentIndex -= 4;
          renderChunk();
        }
      });
    });
  };
}
